# ANTI-PATTERN: Equal task weighting without validation monitoring
class PoorMultiTaskBatsman:
    def __init__(self, shared_encoder):
        self.shared_encoder = shared_encoder
        self.batting_head = TaskHead(hidden_dim=768)  # Runs scored
        self.bowling_head = TaskHead(hidden_dim=768)  # Wickets taken
        self.fielding_head = TaskHead(hidden_dim=768)  # Catches held

    def train_step(self, batch):
        encoded = self.shared_encoder(batch['cricket_input'])
        batting_loss = self.batting_head(encoded, batch['runs'])
        bowling_loss = self.bowling_head(encoded, batch['wickets'])
        fielding_loss = self.fielding_head(encoded, batch['catches'])
        # PROBLEM: No task scaling, no gradient monitoring
        total_loss = batting_loss + bowling_loss + fielding_loss
        return total_loss

# BEST PRACTICE: Dynamic loss weighting with per-task validation tracking
class OptimalMultiTaskBatsman:
    def __init__(self, shared_encoder, task_names=['batting', 'bowling', 'fielding']):
        self.shared_encoder = shared_encoder
        self.task_heads = {task: TaskHead(768) for task in task_names}
        self.task_losses = {task: [] for task in task_names}
        self.loss_weights = {task: 1.0 for task in task_names}
        self.validation_metrics = {task: [] for task in task_names}

    def train_step(self, batch):
        encoded = self.shared_encoder(batch['cricket_input'])
        losses = {}
        for task, head in self.task_heads.items():
            losses[task] = head(encoded, batch[task]) * self.loss_weights[task]
            self.task_losses[task].append(losses[task].detach())

        total_loss = sum(losses.values())
        return total_loss

    def update_loss_weights(self, validation_scores):
        """Rebalance weights based on task performance drift"""
        base_weights = {task: 1.0 for task in self.task_heads.keys()}
        for task, score in validation_scores.items():
            # Increase weight if task performance is degrading
            if score < np.mean(self.validation_metrics[task][-10:]):
                base_weights[task] *= 1.2
            self.validation_metrics[task].append(score)

        # Normalize to prevent unbounded growth
        total_weight = sum(base_weights.values())
        self.loss_weights = {task: w/total_weight for task, w in base_weights.items()}
        return self.loss_weights
